"""
Standalone patch — writes mkt-context for Psalms 103-104 directly.
Run: python3 scripts/zc-context-psalms-103-104-patch.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PSA_CONTEXT = {
  "103": {
    "1": "<p>Psalm 103 is one of the great doxological psalms of YHWH's covenant mercy, attributed to David. It sits within Book IV of the Psalter (Ps 90-106), which is sometimes called the 'Moses book' — Ps 90 is attributed to Moses, and the book is dominated by themes of YHWH's eternal reign and Israel's frailty. 'Bless the LORD, O my soul; let every part of me bless his holy name!' — the self-address formula (addressing one's own nephesh) appears also in Ps 104:1 and 146:1, suggesting a cluster of related psalms using this distinctive form. The summons to bless YHWH is the inverse of petition: not requesting from YHWH but offering to YHWH from the self's whole interior.</p>",
    "2": "<p>'Bless the LORD, O my soul, and forget not a single good thing he has done' — the 'forget not' (al-tishkechi) is the counter-command to the covenant amnesia that destroyed Israel repeatedly (Deut 8:11-14: 'Be careful that you do not forget the LORD ... when you have eaten and are satisfied and built fine houses ... then your heart will become proud and you will forget the LORD your God'). The psalm is a deliberate act of remembering — summoning the soul to active recollection of YHWH's benefits as the antidote to spiritual pride and ingratitude.</p>",
    "3": "<p>'Who forgives every one of your sins, who heals every one of your illnesses' — the two great divine acts of restoration paired: forgiveness (salach, the priestly-covenantal term for divine pardon; Exod 34:9: 'Pardon our iniquity and our sin') and healing. In ancient Israelite thought, sin and illness could be causally linked (cf. Ps 41:4: 'LORD, have mercy on me; heal my soul, for I have sinned against you'). The comprehensive 'every one' (kol) emphasizes total coverage: no sin too numerous to be forgiven, no illness beyond YHWH's healing reach.</p>",
    "4": "<p>'Who redeems your life from destruction, who crowns you with steadfast love and compassion' — 'redeems your life from the pit' (go'el mishachat chayyayich) — the kinsman-redeemer language (go'el, the one who pays the price to liberate a family member from debt or death; Lev 25:25-28; Ruth 4:1-6). YHWH acting as the kinsman-redeemer of his people is the basis for Isa 41:14 ('your Redeemer is the Holy One of Israel') and the entire redemption theology of Second Isaiah. 'Crowns you with steadfast love' — the crown of hesed as the royal adornment YHWH places on the redeemed person.</p>",
    "5": "<p>'Who satisfies you with good things so that your strength is renewed like the eagle's' — the eagle renewal: eagles (nesher, which also covers vultures in Hebrew) were observed to periodically molt and replace their feathers, which ancient observers interpreted as a kind of renewal of youth. The image of the eagle's renewed strength is used in Isa 40:31: 'Those who wait on the LORD will renew their strength; they will soar on wings like eagles; they will run and not grow weary.' The common image connects covenant renewal to the eagle's visible vitality.</p>",
    "6": "<p>'The LORD acts with righteousness and justice for all who are oppressed' — the universalization of YHWH's justice: not only for Israel but 'for all who are oppressed' (le-kol ashuqim). The combination of tsedaqah (righteousness) and mishpatim (justice/judgments) is the standard pairing of YHWH's governance (Ps 89:14; 97:2). The psalm moves from individual benefit (vv. 3-5) to social justice (v. 6) to historical revelation (v. 7) — expanding the scope of divine activity from personal healing to cosmic governance.</p>",
    "7": "<p>'He revealed his ways to Moses and his mighty deeds to the people of Israel' — YHWH's self-revelation has two levels: his 'ways' (derachav, his covenant character and pattern of action) revealed to Moses (the Sinai theophany of Exod 33-34), and his 'mighty deeds' (alilotav) revealed to the broader people (the plagues, Red Sea, wilderness provision). Moses received the deeper revelation — not just the acts but the principles behind them. The revelation to Moses in Exod 34:6-7 is precisely what v. 8 will quote: the thirteen divine attributes (middot) of YHWH's character.</p>",
    "8": "<p>'The LORD is compassionate and gracious, patient in anger and overflowing with steadfast love' — this verse is the direct citation of the Sinai self-revelation formula of Exod 34:6: 'The LORD, the LORD, a God compassionate and gracious, slow to anger and overflowing with steadfast love and faithfulness.' The formula (variously cited in Num 14:18; Neh 9:17; Ps 86:15; 145:8; Joel 2:13; Jonah 4:2; Nah 1:3) is the most frequently cited divine self-description in the OT. It is the theological center of Israel's understanding of YHWH's character: mercy precedes justice, and grace is the dominant note of covenant relationship.</p>",
    "9": "<p>'He does not bring charges forever, nor does he hold on to his anger without end' — the limit on divine anger: YHWH does not prosecute the case indefinitely (lo-yativ lanetsach, he will not contend forever; cf. Isa 57:16: 'I will not accuse forever, nor will I always be angry, for the spirit of man would grow faint before me'). The finite nature of YHWH's anger contrasts with the eternal nature of his hesed (v. 17: 'from age to age'). Anger is the exception; love is the rule. This is the opposite of the ANE storm-god theology where divine wrath could be arbitrary and interminable.</p>",
    "10": "<p>'He has not treated us as our sins deserve, nor paid us back measure for measure for our iniquities' — the explicit statement of grace over strict retributive justice. The principle of measure-for-measure (middah keneged middah) was the standard legal principle of covenant consequence: sin produces proportional consequence (Lev 26; Deut 28). YHWH's grace is precisely that he does not apply this principle strictly: 'he has not dealt with us according to our sins' (lo cha'ta'einu asah lanu). This is the grace embedded in the Sinai formula and the basis for Israel's continued existence as a covenant people despite repeated failure.</p>",
    "11": "<p>'For as high as the heavens are above the earth, so great is his steadfast love for those who fear him' — the spatial comparison of the incomprehensibly large: the distance from earth to heaven (in ancient cosmology, an immeasurably vast distance) is used as the measure of YHWH's hesed. The simile acknowledges that hesed exceeds human comprehension: just as one cannot see the top of the heavens from earth, one cannot fully grasp the extent of YHWH's covenant love. The 'fear of the LORD' as the condition of receiving this vast hesed ties back to the covenant wisdom theme throughout the Psalter.</p>",
    "12": "<p>'As far as east is from west, that is how far he has removed our transgressions from us' — the east-west direction (unlike north-south, which have definable poles/limits) is an infinite distance in ancient thinking: if you travel east, you never reach 'the east'; if you travel west, you never reach 'the west.' The transgressions are not merely forgiven but removed to an infinite distance — the opposite of Ps 90:8 (YHWH setting our sins 'before' him in the light of his face). The removal of sins to an unreachable distance is the spatial metaphor for radical forgiveness.</p>",
    "13": "<p>'Just as a father is tender toward his children, so the LORD is tender toward those who fear him' — the father-child metaphor for divine tenderness is relatively unusual in the OT. The verb racham (be tender/compassionate) shares the root with rechem (womb), connecting paternal tenderness with maternal womb-love. The metaphor appears in Isa 63:16 ('you are our Father, even if Abraham does not know us and Israel does not acknowledge us'), Jer 31:9 ('I am Israel's father, and Ephraim is my firstborn'), and Mal 3:17 ('I will have compassion on them as a man has compassion on his son who serves him'). This familial metaphor is rare but significant.</p>",
    "14": "<p>'He knows exactly what we are made of; he has not forgotten that we are dust' — the divine omniscience applied to human frailty: YHWH knows our 'formation' (yetzer, the word used in Gen 2:7: YHWH 'formed' man from the dust; also Gen 6:5: 'every inclination of the thoughts of the human heart was only evil all the time' — the same yetzer). 'We are dust' (ki aphar anachnu) echoes Gen 2:7 (YHWH formed man from the dust of the ground) and Gen 3:19 ('you are dust and to dust you shall return'). YHWH's mercy is informed by his knowledge of what he created us from.</p>",
    "15": "<p>'As for mortals, their days are like grass; they bloom like a wildflower of the field' — the grass and wildflower imagery for human brevity appears frequently in the OT (Isa 40:6-8: 'All people are grass, and all their constancy is like the flower of the field. The grass withers, the flower fades'; Job 14:1-2; Ps 90:5-6). In the Levantine climate, the spring wildflowers bloom dramatically and then wither rapidly in the summer heat — a vivid annual reminder of human mortality. 1 Pet 1:24-25 cites Isa 40:6-8 (which parallels this passage) to contrast the brevity of human life with the permanence of God's word.</p>",
    "16": "<p>'The wind sweeps over it and it vanishes, and the place where it stood no longer knows it' — the second detail of the wildflower comparison: even its place of growth does not remember it. 'The place no longer knows it' (lo yakkirehu odo) — the complete erasure of the individual plant from memory. In the ancient honor-shame world, one's name being remembered was the form of personal immortality; the wildflower achieves not even this minimal memorial. The contrast with YHWH's eternal hesed (v. 17) is the psalm's central antithesis: human fragility against divine permanence.</p>",
    "17": "<p>'But the steadfast love of the LORD is from age to age over those who fear him, and his righteousness reaches to their children's children' — the contrast: while the human is like grass (vv. 15-16), YHWH's hesed is 'from age to age' (me'olam ve'ad olam, from everlasting to everlasting — the same phrase as the doxologies closing each Psalter book). The intergenerational reach of YHWH's covenant fidelity (to children's children) is the multigenerational covenant promise of Exod 20:6 ('showing steadfast love to a thousand generations of those who love me').</p>",
    "18": "<p>'To those who hold to his covenant and keep his commands in mind to live by them' — the covenant condition: YHWH's hesed extends multigenerationally to those who keep the covenant. 'Hold to his covenant' (shomarei verito) and 'keep his commands in mind' (lefiqudav yizkerum) — the covenant is maintained through active remembrance and observance. The Shema connection (Deut 6:4-9: 'These commandments that I give you today are to be on your hearts ... talk about them') is implicit: keeping the commands 'in mind' to act on them is the standard Deuteronomic formula for covenant fidelity.</p>",
    "19": "<p>'The LORD has set up his throne in the heavens; his kingdom governs everything that exists' — the cosmic scope of YHWH's sovereignty: the divine throne (kisse) in the heavens established from which YHWH's kingdom (malkuto) 'governs everything' (bakkol mashalah). The heavenly throne from which universal governance flows is the same throne as Isa 66:1 ('The heaven is my throne and the earth is my footstool'), Rev 4:2-11 (the heavenly throne room of Revelation), and the inaugural vision of Isa 6:1 ('I saw the Lord sitting on a throne, high and exalted'). The psalm ends where it should: YHWH's cosmic rule as the final affirmation.</p>",
    "20": "<p>'Bless the LORD, you his angels — his mighty warriors who carry out his commands, swift to obey his voice!' — the final three verses of the psalm summon concentric circles of the cosmic community to bless YHWH: angels (v. 20), his armies/servants (v. 21), all his creation (v. 22). The 'mighty warriors' (gibbore koach, warriors of strength) who 'carry out his commands' are the divine council members or heavenly army — the bene elohim of Job 1-2, the 'armies of YHWH' of Ps 89:6-8, and the angelic hosts of Isa 6:1-3 who declare the divine glory. Their defining characteristic is obedience: 'swift to obey his voice.'</p>",
    "21": "<p>'Bless the LORD, all his armies — all who serve him and carry out his purposes!' — the heavenly armies (tseva'av, his hosts) are the same as the 'LORD of Hosts' (Yhwh Tseva'ot) — the armies that YHWH commands. The dual identity (warrior-servants AND covenant-servants) is the essential character of the heavenly beings: they exercise military power entirely in YHWH's service, executing his will. The phrase 'all who serve him' (mesharetav, his ministers/servants) uses the temple-service vocabulary — the heavenly beings are liturgical servants as well as military agents.</p>",
    "22": "<p>'Bless the LORD, everything he has made, in every place his reign extends. Bless the LORD, O my soul!' — the final expansion of the praise circle: from angels (v. 20) to armies (v. 21) to 'everything he has made in every place' — all creation, everywhere. The psalm closes with the same address to the self ('Bless the LORD, O my soul') with which it opened (v. 1), forming a literary inclusio. The entire journey from personal benefit (vv. 3-5) to cosmic governance (v. 19) to universal praise (vv. 20-22) ends where it began: the individual soul summoned to join the universal chorus.</p>"
  },
  "104": {
    "1": "<p>Psalm 104 is one of the great creation hymns of the Bible, closely parallel in structure to Genesis 1 (the seven creation days roughly correspond to the psalm's movements). It bears also striking structural parallels to the Egyptian Great Hymn to the Aten, composed during Pharaoh Akhenaten's monotheistic reform (c. 1353-1336 BCE) — the parallels are so close that scholars have long debated the relationship, though the theological content is entirely different (Aten as the physical sun; YHWH as the creator of all including the sun). 'O LORD my God, how great you are — robed in honor and majesty' — the robe of divine glory is the visual idiom for YHWH's majestic self-presentation.</p>",
    "2": "<p>'Wrapped in light as in a robe, spreading out the heavens like a tent curtain' — light as YHWH's garment: in the ANE, light was a divine attribute (Egyptian pharaoh depicted with sun-disk; Mesopotamian deities with the melammu, divine radiance). For YHWH, light is not divine substance but clothing — something donned, something created (Gen 1:3: 'Let there be light'). 'Spreading out the heavens like a tent curtain' (notheh shamayim kayerayah) — the heavens as a tent fabric stretched across the sky, an image also in Isa 40:22: 'He stretches out the heavens like a curtain and spreads them out like a tent to live in.'</p>",
    "3": "<p>'He sets the beams of his upper rooms on the waters; he mounts the clouds as his chariot; he travels on the wings of the wind' — the cosmic palace: YHWH's upper chambers (aliyyotav, his upper rooms/loft) rest on the upper waters above the firmament (Gen 1:7: YHWH divided the waters above the firmament from those below). The cloud-chariot of YHWH (the rider of clouds) is also the title of Baal in Ugaritic mythology (rkb 'rpt, the cloud-rider); Ps 68:4 applies the same title to YHWH. The 'wings of the wind' (kanfei ruach, wings of the spirit/wind) are the divine movement through the created order.</p>",
    "4": "<p>'He makes the winds his messengers and flashing fire his servants' — in the ANE, winds and lightning were attributes of the storm deity (Baal/Hadad). The psalm demythologizes: the winds are not divine agents with their own purposes but YHWH's messengers (mal'achav, his angels/messengers) and instruments. Hebrews 1:7 cites this verse to establish the inferiority of angels to the Son: 'He makes his angels winds, his servants flames of fire' — angels are created instruments; the Son is the eternal one through whom all things were made (Heb 1:3, 10-12 citing Ps 102).</p>",
    "5": "<p>'He fixed the earth on its foundations so that it will never be shaken' — the ancient cosmology: the earth rests on foundations (mekono, its established place) that YHWH set in place. In the ancient Near East, the earth was conceived as resting on pillars (1 Sam 2:8: 'the pillars of the earth belong to YHWH'), columns set in the primordial waters (Job 38:4-6: 'Where were you when I laid the foundations of the earth? ... Who set its cornerstone?'). The earth's stability is not inherent but divinely maintained — it 'will never be shaken' (bal-timot leolam) because YHWH sustains it.</p>",
    "6": "<p>'You covered it with the deep like a cloak; the waters towered above the mountains' — the primordial state before YHWH's ordering: the entire earth covered by the deep (tehom, the primordial waters of Gen 1:2: 'darkness was over the surface of the deep'). The waters 'towered above the mountains' — the entire geological landscape submerged in the pre-creation condition. The psalm is narrating the transition from chaos to creation as YHWH's victory over the undifferentiated deep.</p>",
    "7": "<p>'At your rebuke they retreated; at the sound of your thunder they fled in haste' — the divine rebuke (gaarat, your rebuke/scolding) drives the primordial waters back. The same verb is used in Ps 18:15 (at YHWH's rebuke, the channels of the sea were revealed at the Exodus) and Isa 50:2 (YHWH's rebuke that dries up the sea). YHWH's 'thunder' (qolecha, your voice — the thunder that accompanies divine theophany) is the divine war-cry against the chaos waters. This is the Chaoskampf (cosmic battle) motif: YHWH defeating the chaos waters through authoritative speech rather than violent combat.</p>",
    "8": "<p>'The mountains rose and the valleys sank to the places you had set for them' — the creative ordering: as the waters retreated (v. 7), the geological landscape took its ordained shape. Mountains rising and valleys sinking describe the differentiation of terrain that resulted from the waters being bounded. 'The places you had set for them' (el-meqom zeh yasadta lahem) — the creation as YHWH's purposive ordering: each part of the landscape occupies the place YHWH designated for it. The world is not random but intentionally arranged.</p>",
    "9": "<p>'You drew a boundary they cannot cross, so the waters will never again engulf the earth' — the covenant with creation: the waters are given a boundary (gevul) they cannot transgress. This is the same promise as Gen 9:11 (the Noahic covenant: 'Never again will there be a flood to destroy the earth') and Job 38:10-11 ('I fixed limits for it and set its doors and bars in place ... here is where your proud waves halt'). The boundary drawn at creation is YHWH's covenant with the natural order — the guarantee of continued habitable creation.</p>",
    "10": "<p>'He sends springs into the valleys; they run between the hills' — the positive provision after the negative boundary: the same waters that threatened at creation are now bounded and channeled to provide life. Springs (mayan, sources of fresh water) sent into the valleys (nachel, seasonal watercourses/wadis) are the productive management of the water that was previously threatening. The creation narrative moves from chaos (vv. 6-9) to order (vv. 10-18): YHWH's sovereign management of water makes the earth productive.</p>",
    "11": "<p>'Giving water to every wild animal; the wild donkeys slake their thirst there' — the ecological cascade: springs sustain wild animals that could not otherwise survive in the arid landscape. The 'wild donkeys' (pere, the wild ass — a symbol of untameable wildness in the OT; Job 39:5-8: 'Who let the wild donkey go free? Who untied his ropes? I gave him the wasteland as his home') are sustained by YHWH's provision of springs. Even the untameable creatures of the wilderness live within the economy of divine provision.</p>",
    "12": "<p>'Along their banks the birds of the sky make their homes and sing among the branches' — the cascading ecosystem: water produces vegetation, vegetation provides nesting sites for birds, birds provide sound (the 'singing among the branches' yittenu-qol, give voice). The creation is not merely functional but beautiful: the birds' song is part of the ordered creation's response to YHWH's provision. The delight of the created order in its own existence is reflected in this detail of birds nesting and singing by the water.</p>",
    "13": "<p>'From his upper chambers he sends rain down the mountains; the earth is filled by what he provides' — the hydrological cycle: YHWH's upper chambers (aliyyotav, from which he works in v. 3) are the source of rain that descends from the mountains to fill the earth. The 'fruit of your works' (peri ma'asecha) that fills the earth is everything that YHWH has produced through the watering process — the agricultural and ecological abundance that results from divinely provided rain. The earth's fullness is YHWH's work-product.</p>",
    "14": "<p>'He makes grass grow for the cattle and plants for people to tend so they can bring food out of the ground' — the agricultural theology: YHWH directly produces the grass for animals and enables human cultivation to bring food from the soil. In the ANE, agricultural fertility was attributed to the fertility deities (Baal, Asherah, Osiris); Psalm 104 reassigns this to YHWH. The human role ('for people to tend') is collaborative, not independent: humans work the land that YHWH waters and fertilizes. The Genesis mandate (Gen 1:28-29; 2:15) to cultivate the earth is embedded in the psalm's agricultural section.</p>",
    "15": "<p>'Wine that lifts the human heart, oil that makes the face glow, and bread that gives strength to the body' — the three primary agricultural products of the ancient Levantine economy: wine (from grapes), oil (from olives), and bread (from grain). These three appear together throughout the OT as the comprehensive summary of agricultural bounty (Deut 7:13; 11:14; Ps 4:7: 'You have put more joy in my heart than they have when their grain and wine abound'; Prov 9:5). The 'glowing face' from oil — ancient olive oil was used cosmetically to make the face shine — and wine 'lifting the heart' describe the specific human pleasures that these three products provide.</p>",
    "16": "<p>'The trees of the LORD drink deeply — the great cedars of Lebanon that he himself planted' — the 'trees of the LORD' (atsai-Yhwh) are YHWH's own trees, not human plantations. The great cedars of Lebanon were the most impressive trees in the ancient Near Eastern world — used in the construction of Solomon's temple (1 Kgs 5:6-10; 7:2: the 'Palace of the Forest of Lebanon'), prized for their massive size and fragrant wood. YHWH 'planted' these trees — they belong to him and sustain their own life from his provision, independent of human cultivation.</p>",
    "17": "<p>'There the birds build their nests; the stork finds her home in the cypress trees' — the ecosystem of the great cedars: the trees provide habitat for bird communities. The stork (chasidah, the faithful one — named for its presumed loyalty) nesting in the cypress is a detail of the natural world's ordered community. In the ancient world, the stork's annual return was a sign of the seasons (Jer 8:7: 'the stork in the sky knows her appointed seasons'). YHWH's creation has built-in ecological niches: each creature has a designed habitat within the larger system.</p>",
    "18": "<p>'The rugged mountains belong to the wild goats; the rocky crags shelter the rock badgers' — the ecological assignment of habitat: the high mountains (harim hagevohim, the high mountains) are given to the wild goats (yaalim, ibexes — adapted to cliff terrain), and the rocks to the rock badgers (shefannim, hyraxes — small, rabbit-like creatures that live in rock crevices; Prov 30:26: 'the hyrax — though a weak creature — lives among the crags'). The wild spaces that humans cannot easily inhabit are nonetheless populated by creatures perfectly suited to them — each creature in its divinely assigned habitat.</p>",
    "19": "<p>'He appointed the moon to mark the seasons; the sun knows exactly when to set' — the temporal ordering through the luminaries. The moon (yareach) marks the appointed times (mo'adim, the festival calendar; Gen 1:14: 'let them be for signs and for seasons, and for days and years'). In Israelite practice, the lunar calendar governed the religious festivals (Passover, Firstfruits, Weeks, Trumpets, Atonement, Tabernacles). The sun 'knowing when to set' (yada mevo'o, knows its going in/setting) personifies the sun as YHWH's obedient servant, in deliberate contrast to ANE solar theology where the sun had its own divine will.</p>",
    "20": "<p>'You bring on darkness and it becomes night, when all the forest creatures stir' — the nocturnal world as YHWH's creation. Night, which in ANE thought was often the domain of chaos and demonic powers, is here YHWH's purposive ordering for the nocturnal creatures. 'All the forest creatures stir' (tirmosh kol chayto-yaar, all the animals of the forest creep about) — the night belongs to YHWH's creation as fully as the day. The darkness that YHWH 'brings on' is not the absence of his governance but its continuation through the night cycle.</p>",
    "21": "<p>'The young lions roar as they hunt, looking to God for their food' — the theological claim that is the psalm's most striking anthropomorphism: the lions hunting in the night are 'seeking their food from God' (levaqesh me'el achlam, to seek from God their food). The predatory behavior of lions is built into YHWH's creation and is itself an act of dependence on YHWH — the lions' roar is their form of prayer. This is the opposite of ANE predator mythology where the lion as divine symbol represented autonomous power; here the lion is as dependent on YHWH as the grass-grazing cattle.</p>",
    "22": "<p>'When the sun comes up, they slip away and stretch out in their lairs' — the day/night cycle as an ordered alternation of human and animal activity. The lions' withdrawal at sunrise into their dens (yirbetsun, they lie down in their dens) corresponds to the human emergence to work (v. 23). The same temporal order that governs human farming (v. 23) also governs predator hunting (v. 21). YHWH's creation has built-in temporal rhythms that prevent constant conflict between species: the lion's time (night) and the human's time (day) are separated by the sunrise.</p>",
    "23": "<p>'Then people go out to their work and labor on until the evening' — human work as part of the cosmic order: the humans emerge at sunrise for their daily labor (avodat, their work/service) until evening. The rhythm of human work within the day/night cycle is itself part of YHWH's creation order — not the curse of Gen 3:17-19 alone (though that passage adds the element of toil) but the positive vocation of Gen 2:15 (to work and keep the garden). The psalm presents human labor as woven into the fabric of the ordered creation.</p>",
    "24": "<p>'LORD, what a multitude of works you have made! You crafted them all in wisdom; the earth is full of what belongs to you' — the wisdom-creation connection: YHWH crafted the creation 'in wisdom' (bekhokhmah asitam, you made them all in wisdom). The same connection appears in Prov 8:22-31, where Wisdom was present at creation as YHWH's 'craftsman' (amon, master-craftsman). The creation's complexity and beauty are expressions of divine wisdom — not random but rationally structured. 'The earth is full of what belongs to you' (qinyanecha, your possessions/creatures) asserts YHWH's comprehensive ownership of all created things.</p>",
    "25": "<p>'And here is the sea — vast and wide — teeming with creatures beyond counting, great and small alike' — the sea (yam, the Mediterranean or the great ocean) as a teeming, inhabited space. 'Beyond counting' (ein mispar, without number) — the sea's creatures exceed human capacity to enumerate. In ANE cosmology, the sea was the domain of chaos and threat; in Ps 104 it is a vibrant, inhabited habitat within the ordered creation. The same chaos-waters that threatened in vv. 6-9 are now a teeming ecosystem — the Chaoskampf has been completely resolved into productive order.</p>",
    "26": "<p>'The ships sail there, and there is Leviathan, which you formed to frolic in the deep' — the most astonishing verse in the psalm: Leviathan (the chaos monster of Ugaritic mythology, the many-headed sea dragon that Baal killed in mortal combat, also the monster of Job 40:25-41:26) is here reduced to a creature 'formed' (yatsarta, same verb as Gen 2:7 where YHWH forms man) by YHWH 'to frolic in the deep' (lesachek-bo, to play in it). The chaos monster is YHWH's plaything — created to amuse itself in the sea. The theological demotion of Leviathan from terrifying chaos-god to divine toy is one of the most dramatic demythologizations in the OT.</p>",
    "27": "<p>'All of these look to you to give them their food when they need it' — the comprehensive dependence of all creatures on YHWH for sustenance. 'All of these look to you' (kulam eleicha yesabberun, all of them wait expectantly toward you) — the entire animal world in a posture of expectant dependence. The same posture the psalmist takes toward YHWH in petition (waiting, hoping) is the natural condition of all creatures toward their creator. Every creature — from the lions hunting at night (v. 21) to Leviathan playing in the sea (v. 26) — subsists on YHWH's provision.</p>",
    "28": "<p>'When you give, they gather it in; when you open your hand, they are satisfied with good' — the 'open hand' of YHWH providing for creation echoes Ps 145:16 ('You open your hand and satisfy the desires of every living thing'). The open hand as the gesture of generous giving is a consistent image of divine provision. The creatures' 'gathering' (yilqotun, they gather up) and 'satisfaction with good' (yisbeu tov, they are satisfied with good) mirror exactly the Exodus provision of manna: YHWH opens his hand, the people gather, and they are satisfied.</p>",
    "29": "<p>'If you hide your face, they are terrified; if you take back their breath, they die and return to dust' — the hiddenness of the divine face (astir panecha, you hide your face) as the cause of cosmic terror — the same face-hiding as in the lament psalms (Ps 13:1; 27:9; 44:24) but now applied to the entire creation. If YHWH withdraws his sustaining attention, all creatures are terrified and die. 'Take back their breath' (tosaph ruacham, you gather back their spirit/breath) — the ruach (breath/spirit) of all creatures is YHWH's to give and to reclaim (Gen 2:7: YHWH breathed the breath of life into man; Eccl 12:7: 'the spirit returns to God who gave it').</p>",
    "30": "<p>'When you send out your Spirit, they are created, and you renew the surface of the earth' — 'you send out your Spirit' (teshalach ruchacha, you send your Spirit) — the divine Spirit (ruach) as the creative agent of YHWH: the same ruach hovering over the waters in Gen 1:2 that initiated creation. The Spirit's dispatch produces creation (yibbareun, they are created) and renewal of the earth's surface. This verse is the theological foundation for the NT's connection between the Spirit and new creation: 2 Cor 5:17 ('if anyone is in Christ, the new creation has come'), Acts 2 (the Spirit poured out at Pentecost as new creation event).</p>",
    "31": "<p>'May the glory of the LORD last forever; may the LORD take delight in what he has made!' — the prayer that YHWH's glory (kavod, his weighty, radiant presence) would be eternal and that YHWH would 'delight' (yismach, rejoice) in his creation. Gen 1:31 ('God saw all that he had made, and it was very good') is the basis for this prayer: YHWH the creator who saw his work as 'very good' is invited to continue rejoicing in it permanently. The creation's ongoing existence is grounded in YHWH's ongoing delight — if he ceased to delight, he might cease to sustain.</p>",
    "32": "<p>'He looks at the earth and it shakes; he touches the mountains and they pour out smoke' — the theophanic power of YHWH's gaze and touch: the earth quakes at his look (yibbat la'arets vatyir'ad) and mountains smoke at his touch (yigga' beharim veye'eshanu). These are the phenomena of Sinai (Exod 19:18: 'Mount Sinai was covered with smoke, because the LORD descended on it in fire'; Ps 68:8: 'the earth shook, the heavens poured down rain before God') and of YHWH's theophanic appearances in Amos (8:8; 9:5) and Nahum (1:5). The creator who sustains the earth (v. 5) is also the one whose power causes it to tremble.</p>",
    "33": "<p>'I will sing to the LORD as long as I live; I will sing praise to my God for as long as I draw breath' — the vow of lifelong praise: the cosmic creation hymn (vv. 1-32) resolves into the individual's personal commitment of praise 'as long as I live' (bechayay, in my life/lifetime) and 'as long as I draw breath' (be'odi, while I still exist). The vast scope of the creation psalm (from primordial waters to Leviathan to the divine Spirit) ends with the individual worshiper's personal vow — the microcosm of personal devotion within the macrocosm of cosmic praise.</p>",
    "34": "<p>'May my thoughts about him be sweet to him, as I find my joy in the LORD' — the prayer for the psalmist's own meditation (sichi, my meditation/conversation/prayer) to be acceptable ('sweet,' arev, pleasing) to YHWH. This is the reverse of the standard petition: the psalmist prays not that YHWH would give something to him but that what the psalmist offers to YHWH would be received with pleasure. The joy (simach, I will rejoice/be glad) in YHWH as the psalmist's ultimate satisfaction closes the personal dimension of the hymn.</p>",
    "35": "<p>'Let sinners vanish from the earth and let the wicked exist no longer! Bless the LORD, O my soul! Hallelujah!' — the psalm's striking ending: the creation hymn closes with an imprecatory prayer against sinners and wicked ones, then the return of the opening address ('Bless the LORD, O my soul') and the first occurrence of 'Hallelujah' (hallelu-Yah, praise Yah/YHWH) in the Psalter. Hallelujah will become the dominant liturgical expression of Books IV-V (Ps 104-150). Its meaning — a plural imperative calling the assembled community to praise — makes it a corporate summons, taking the individual psalmist's closing praise into the communal liturgy.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'psalms')
    merge_comm(c, PSA_CONTEXT)
    save_comm('mkt-context', 'psalms', c)
    total_v = sum(len(vv) for vv in c.values())
    print(f'Psalms context: {len(c)} chapters, {total_v} verses')

if __name__ == '__main__':
    main()
